import{_ as o,o as t,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"63. Long Service Leave","description":"","frontmatter":{"title":"63. Long Service Leave","eba":"Biomedical Engineers 2025-2028","topics":["leave","personal-leave","annual-leave","long-service-leave"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/63-long-service-leave.md","filePath":"ebas/biomedical-engineers/leave/63-long-service-leave.md"}'),r={name:"ebas/biomedical-engineers/leave/63-long-service-leave.md"};function i(s,e,l,p,c,m){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_63-long-service-leave" tabindex="-1">63. Long Service Leave <a class="header-anchor" href="#_63-long-service-leave" aria-label="Permalink to &quot;63. Long Service Leave&quot;">​</a></h1><p>Casual Employees are entitled to Long Service Leave in accordance with the Long Service Leave Act 2018 (Vic) (or applicable legislation).</p><p><strong>63.1</strong> Definitions The following meanings shall apply to the terms referred to below for the purposes of this clause unless a contrary intention is apparent:</p><p><strong>(a)</strong> Allowable Period of Absence means five weeks in addition to the total period of paid annual leave and/or personal leave that the Employee actually receives on termination, or for which they are paid in lieu.</p><p><strong>(b)</strong> Continuous Service means continuous service with the same Employer plus any prior continuous service of six months or more with one or more Employers covered by this Agreement, an Institution or a Statutory Body.</p><p><strong>(c)</strong> Continuous Casual Employment means, for the purpose of this clause, a period or periods of casual employment with the same Employer that are taken to be continuous, because one of the following applies:</p><p><strong>(i)</strong> the period starting at the end of a particular instance of employment and ending at the start of another particular instance of employment did not exceed either the Allowable Period of Absence, or 12 weeks (whichever is greater); or</p><p><strong>(ii)</strong> one of the circumstances described in section 12(3) of the LSL Act applies, namely: <strong>(A)</strong> the casual Employee had been employed by an Employer on a regular and systematic basis and the casual Employee had a reasonable expectation of being re-engaged by the same Employer; or <strong>(B)</strong> any absence was due to the terms of engagement of the casual employee; or <strong>(C)</strong> any absence was caused by seasonal factors; or <strong>(D)</strong> the casual Employee and Employer agreed, before the start of an absence, to treat the employment as continuous despite the absence.</p><p><strong>(d)</strong> Full-time Employee means an Employee classified or employed as such at the time they apply for or commence long service leave;</p><p><strong>(e)</strong> Institution means any hospital or benevolent home, community health centre, Society or Association registered and subsidised pursuant to the Health Services Act 1988 (Vic), the Cancer Institute constituted under the Cancer Act 1958 (Vic) or the Fairfield Hospital Board or the Bush Nursing Association (Inc).</p><p><strong>(f)</strong> LSL Act means the Long Service Leave Act 2018 (Vic).</p><p><strong>(g)</strong> Month means a calendar month.</p><p><strong>(h)</strong> Pay means, for a Full-time Employee or Part-time Employee, the remuneration for an Employee’s normal weekly hours of work calculated at the Employee’s ordinary time rate of pay at the time the leave is taken or (if they die before the completion of leave so taken) as at the time of their death, and will include the</p><p>amount of any increase to the Employee’s ordinary time rate of pay which occurred during the period of leave as from the date of such increase operates. Where a part-time Employee&#39;s hours fluctuate because the Employee works additional ordinary shifts (but excluding a permanent variation), the &#39;normal weekly hours of work&#39; will be calculated by taking an average over the preceding 12 months where this is more favourable to the Employee.</p><p><strong>(i)</strong> Part-time Employee means an Employee classified or employed as such at the time they apply for or commence long service leave;</p><p><strong>(j)</strong> Statutory Body means the former Hospitals and Charities Commission (Vic) and its successors, the Victorian Department of Health and/or its predecessors and successors.</p><p><strong>(k)</strong> Transfer of business occurs in the circumstances described at section 311 of the Act.</p><p><strong>63.2</strong> Entitlement</p><p><strong>(a)</strong> Subject to subclause 63.4, Full-time and Part-time Employees are entitled to:</p><p><strong>(i)</strong> six months&#39; long service leave with Pay on completion of fifteen years of Continuous Service; and</p><p><strong>(ii)</strong> thereafter, an additional two months&#39; long service leave with Pay on completion of each additional five years of Continuous Service.</p><p><strong>(b)</strong> Subject to subclause 63.4(d) and (e), the entitlement under subclause 63.2(a) may be taken in advance on a pro rata basis if the Employee has accrued at least 7 years’ Continuous Service.</p><p><strong>63.3</strong> Calculating Continuous Service</p><p><strong>(a)</strong> Periods that count towards Continuous Service Service or prior service during the following periods will be deemed to be continuous and will count as Continuous Service for the purpose of subclause 63.1(b):</p><p><strong>(i)</strong> an absence from work on any form of paid leave approved in writing by the Employer (e.g. annual leave, personal leave, long service leave and paid parental leave);</p><p><strong>(ii)</strong> any interruption or ending of employment by the Employer if made with the intention of avoiding obligations in respect of long service leave or annual leave;</p><p><strong>(iii)</strong> up to the FFPPOOA commencement of the Agreement, any absence on account of illness or injury arising out of or in the course of the employment of the Employee for a period during which an Employee is receiving accident make-up pay (see <a href="/eba/ebas/biomedical-engineers/wages/32-accident-make-up-pay.html">clause 32</a>);</p><p><strong>(iv)</strong> a period of absence on community service leave under the Act;</p><p><strong>(v)</strong> any absence from employment on defence service in accordance with section 8 of the Defence Reserve Service (Protection) Act 2001 (Cth);</p><p><strong>(vi)</strong> in the case of casual employment: <strong>(A)</strong> periods of Continuous Casual Employment with the current Employer (in a role covered by this Agreement); and <strong>(B)</strong> prior Continuous Casual Employment of six months or more that was with one or more Employers, Institutions, or Statutory Bodies;</p><p><strong>(vii)</strong> in the case of unpaid absences not otherwise referenced in this subclause:</p><p><strong>(A)</strong> any unpaid leave that is authorised in advance in writing by the Employer to count as service; or <strong>(B)</strong> up to the FFPPOOA commencement of the Agreement, any unpaid absence from work of not more than fourteen days in any year on account of illness or injury; or <strong>(C)</strong> on and from the FFPPOOA commencement of the Agreement: (1) any period of unpaid leave taken on account of illness or injury; (2) a period of Parental Leave, including Parental Leave that is extended under subclause 61.12; and (3) the first 52 weeks of any other type of unpaid leave not specifically referenced in this subclause, save that if long service leave was already taken or paid in lieu in respect of any period referred to above, no further benefit to long service leave will arise in respect of that period.</p><p><strong>(b)</strong> Periods that do not break Continuous Service, but do not count towards Continuous Service Unless otherwise agreed in writing in advance between the Employer and the Employee, the following periods do not break Continuous Service but do not count towards an Employee’s Continuous Service for the purpose of calculating the employee&#39;s long service leave entitlement:</p><p><strong>(i)</strong> any authorised period of unpaid leave not referred to in subclause 63.3(a);</p><p><strong>(ii)</strong> any period between the engagement with one Employer, Institution or Statutory Body and another provided it is equal to or less than the Allowable Period of Absence;</p><p><strong>(iii)</strong> the dismissal of an Employee if the Employee is re-employed by the same Employer within a period not exceeding two months from the date of such dismissal;</p><p><strong>(iv)</strong> subject to the requirements of the Act, any interruption arising directly or indirectly from an industrial dispute;</p><p><strong>(v)</strong> up to the FFPPOOA commencement of the Agreement, any absence on account of injury arising out of or in the course of their employment not covered by a period in which the Employee is receiving accident make up pay or other paid leave; and</p><p><strong>(vi)</strong> any absence from work for a period not exceeding 12 months in respect of a pregnancy, where the pregnancy is not covered by subclause 63.3(a)(i) or 63.3(a)(vii).</p><p><strong>(c)</strong> Transfer of business Where a Transfer of Business occurs, an Employee who worked with the old Employer and who continues in the service of the new Employer will be entitled to count their service with the old employer as service with the new Employer for the purposes of this clause.</p><p><strong>(d)</strong> Proof of sufficient aggregate of service The onus of proving a sufficient aggregate of service to support a claim for any long service leave entitlement will at all times rest upon the Employee concerned. A Certificate of Service in the same or a similar form as <a href="/eba/ebas/allied-health/appendices/4-classification-definitions.html">Appendix 4</a> will constitute acceptable proof.</p><p><strong>63.4</strong> Taking of leave</p><p><strong>(a)</strong> When leave is to be taken</p><p><strong>(i)</strong> Subject to subclause 63.4(a)(ii), an Employee must be granted long service leave within six months from the date of the entitlement arising under subclause 63.2(a). By agreement, the taking of the leave may be postponed to such a date mutually agreed, or in default of agreement, by determination of the Commission (provided that no such determination shall require the leave to commence before the expiry of six months from the date of such determination); and</p><p><strong>(ii)</strong> An Employee of Northern Health who is able to take a period of long service leave under this clause may nominate their preferred date(s) for the taking of leave, save that the Employer may refuse the date(s) so nominated on reasonable business grounds.</p><p><strong>(b)</strong> How leave is to be taken</p><p><strong>(i)</strong> Subject to subclause 63.4(b)(ii), an Employee may request to take long service leave as a single entitlement or in multiple separate periods, with each period being not less than 1 week.</p><p><strong>(ii)</strong> An Employee may request to take long service leave for a period of less than one week (with each period being no less than one (1) day) if: <strong>(A)</strong> the Employee is employed by Northern Health; or <strong>(B)</strong> the Employee is employed by a different Employer, and the Employer can reasonably accommodate the request.</p><p><strong>(iii)</strong> By agreement, Employees may also utilise their long service leave entitlements as part of a Transition to Retirement in accordance with clause 25.</p><p><strong>(c)</strong> Payment for period of leave</p><p><strong>(i)</strong> Payment will be made in one of the following ways: <strong>(A)</strong> in full advance when the Employee commences their leave; <strong>(B)</strong> at the same time as payment would have been made if the Employee had remained on duty; or <strong>(C)</strong> in any other way agreed between the Employer and Employee.</p><p><strong>(ii)</strong> Where an Employee has been paid in advance, and an increase to the Employee&#39;s ordinary time rate of pay occurs during the period of long service leave taken, the Employee will be entitled to receive payment of the amount of any increase in pay at the completion of such leave.</p><p><strong>(d)</strong> Long service leave in advance</p><p><strong>(i)</strong> An Employee who is not eligible to take long service leave (including on a pro rata basis under subclause 63.2(b)) may request to take leave in advance by mutual agreement with the Employer.</p><p><strong>(ii)</strong> If an Employee takes long service leave in advance, the Employee is not subsequently entitled to any further long service leave or payment in lieu of long service leave for the period of employment in respect of which the leave in advance was taken.</p><p><strong>(iii)</strong> If an Employee takes long service leave in advance, and the Employee’s employment ends before the entitlement has manifested, the Employer may deduct from any payment payable to the Employee as a result of the ending</p><p>of the employment, an amount equal to the amount paid to the Employee for the leave, in respect of which the Employee will not become entitled.</p><p><strong>(e)</strong> Flexible taking of leave</p><p><strong>(i)</strong> An Employer may approve an application by an Employee to take double the period of long service leave at half Pay, or half the quantum of leave at double Pay (as the case may be). An Employer&#39;s approval under this clause will not be unreasonably withheld.</p><p><strong>(ii)</strong> Employees should seek independent advice regarding the taxation and superannuation implications of seeking payment under this subclause 63.4(e). The Employer will not be held responsible in any way for the cost or outcome of any such advice.</p><p><strong>(iii)</strong> The Employer, if requested by the Employee, will provide information as to the amount of tax the Employer intends to deduct where payment of long service leave is sought under subclause 63.4(e)(i).</p><p><strong>(iv)</strong> If granting the request under this sub-clause would result in an additional cost to the Employer, the Employer may refuse the Employee&#39;s request.</p><p><strong>(v)</strong> Flexible taking of long service leave does not affect an Employee&#39;s period of Continuous Service recognised. For example, an employee taking 12 months of long service leave at half pay will, for the purpose of calculating continuous service, have six months of continuous service recognised.</p><p><strong>(f)</strong> Payment in lieu of long service leave during employment An Employee may not cash out, or receive payment in lieu of accrued long service leave, except in accordance with clauses 63.4(e) and 63.5.</p><p><strong>(g)</strong> Public holidays Long service leave is inclusive of Public Holidays. See also <a href="/eba/ebas/biomedical-engineers/leave/50-public-holidays.html">clause 50</a> (Public Holidays).</p><p><strong>63.5</strong> Payment on termination of employment</p><p><strong>(a)</strong> Interpretation For the purposes of this subclause 63.5, termination of employment has its ordinary meaning, provided that it is taken to occur upon conversion from Full-time Employment or Part-time Employment to casual employment.</p><p><strong>(b)</strong> Basic entitlement at termination of employment Except where an election is made under subclause 63.5(c) below, an Employee with an entitlement to long service leave under subclause 63.2 is entitled to payment in lieu of untaken long service leave upon termination of employment, calculated as follows:</p><p><strong>(i)</strong> if the termination occurs by reason of serious or wilful misconduct and the employee has accrued less than fifteen years&#39; Continuous Service, one sixtieth of the period of Continuous Service; or</p><p><strong>(ii)</strong> subject to subclause 63.4, if the termination occurs for any other reason, one thirtieth of the period of Continuous Service.</p><p><strong>(c)</strong> Election for payment of entitlement or transfer of entitlement at termination</p><p><strong>(i)</strong> A Full-time or Part-time Employee who has an entitlement to take long service leave on a pro rata basis under subclause 63.2(b) (who therefore has less than 15 years&#39; Continuous Service) and who intends to be re-employed by another Employer as a Full-time or Part-time Employee may:</p><p><strong>(A)</strong> request in writing that payment for accrued long service leave be deferred until after the Employee’s Allowable Period of Absence (as defined above) has expired; and <strong>(B)</strong> where the Employee notifies the initial Employer in writing within the Allowable Period of Absence that the Employee has been employed as an Employee by another Employer, the initial employer is no longer required to make payment to the Employee in respect of such service.</p><p><strong>(ii)</strong> Where the notice referred to at 63.5(c)(i)(B) is not provided prior to or within the Allowable Period of Absence, the Employer will, upon the expiration of the allowable period of absence, make payment in lieu of long service leave as per subclause 63.5(b).</p><p><strong>(iii)</strong> For the removal of doubt, an Employee who has an entitlement to take long service leave under subclause 63.2(a) may not make an election under this clause in respect of that entitlement.</p><p><strong>(d)</strong> Payment in lieu of long service leave on the death of an Employee Where an Employee who has an entitlement to long service leave (or pro rata long service leave) under subclause 63.2 dies while still in the employ of the Employer, payment in lieu of long service leave will be made to the Employee’s personal representative equal to that in clause 63.5(b) above.</p><p><strong>63.6</strong> Transitional Arrangements for Parental Leave taken after 1 November 2018 and before the FFPPOOA commencement of the Agreement Note 1: Unpaid Parental Leave taken prior to 1 November 2018 does not count as Continuous Service unless otherwise agreed, per subclause 63.3(a)(vii)(A). Note 2: Unpaid Parental Leave taken after the FFPPOOA commencement of the Agreement will constitute Continuous Service, per subclause 63.3(a)(vii)(C)(2).</p><p><strong>(a)</strong> As an exception to subclause 63.3(b), an Employee who took a period of unpaid Parental Leave that included any part of the period between 1 November 2018 and FFPPOOA commencement of the Agreement (inclusive) may have that service recognised for Long Service Leave purposes in the following circumstances:</p><p><strong>(i)</strong> where the period of parental leave was taken with the Employee&#39;s current employer, and the Employer confirms in writing that the parental leave will be recognised for Long Service Leave purposes. Where this occurs, the Employer will ensure that the period is reflected in the Employee&#39;s Certificate of Service at the time their employment ceases; or</p><p><strong>(ii)</strong> where the Employee makes a written application to their Employer for recognition of that service in the form required by the Employer. The Employer will approve any such application and provide to the Employee an updated Certificate of Service reflecting the adjusted service arrangements.</p><p><strong>(b)</strong> An Employee electing to make an application under 63.6(a)(ii) must make the application to the Employer no later than 6 months of the following (whichever occurs last):</p><p><strong>(i)</strong> the date on which this Agreement commences; or</p><p><strong>(ii)</strong> the date on which the Employee returns to work after the qualifying period of unpaid Parental Leave.</p><p><strong>(c)</strong> This subclause 63.6 shall apply to an Employee in respect of a former employer if the Employee took a qualifying unpaid period of Parental Leave under this clause while employed by that former employer.</p><p><strong>63.7</strong> Records The Employer will keep a long service leave record for each Employee, containing particulars of service, leave taken, and payments made.</p><p><strong>63.8</strong> Savings No Employee shall suffer any detriment as a result of the operation of this clause to their entitlement to long service leave existing immediately prior to the coming into force of this clause.</p><p>Plain language terms: LSL.</p>',87)])])}const d=o(r,[["render",i]]);export{u as __pageData,d as default};
